import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XssSecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");

        // Sanitize and encode user input before displaying it in the response
        String sanitizedInput = sanitizeInput(userInput);
        out.println("User input: " + sanitizedInput);

        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String userInput) {
